"use strict";(globalThis.webpackChunktype=globalThis.webpackChunktype||[]).push([[8130],{7735(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"first-blog-post","metadata":{"permalink":"/blog/first-blog-post","source":"@site/blog/2026-03-29-first-blog-post.md","title":"First Blog Post","description":"Quite terrifying...","date":"2026-03-29T00:00:00.000Z","tags":[{"inline":false,"label":"Hello","permalink":"/blog/tags/hello","description":"Hello tag description"},{"inline":false,"label":"homeCore","permalink":"/blog/tags/homeCore","description":"homeCore tag description"}],"readingTime":0.77,"hasTruncateMarker":true,"authors":[{"name":"John Eubanks","title":"Mostly Useless Generalist","url":"https://www.linkedin.com/in/eubanksj/","page":{"permalink":"/blog/authors/eubanks"},"key":"eubanks"}],"frontMatter":{"slug":"first-blog-post","title":"First Blog Post","authors":["eubanks"],"tags":["hello","homeCore"]},"unlisted":false},"content":"Quite terrifying...\\n\\n\x3c!-- truncate --\x3e\\n\\nYes.  Terrifying.  This is my first blog post for the homeCore.io blog.  I have no idea what to write about, \\nbut I know that I want to write about something.  So here we are. \\n\\nThis is my first large project that I have ever released to the public.  Exicited, terrified and waiting for the negativity,\\nand AI bashing to come.  Yes AI was used for this project.  I\'m a systems engineer not a developer.  I have been involved\\nin home automation for a very long time and developed numerous plugins, drivers, etc for many other home automation systems.\\nI always found something lacking in all of those systems.  I wanted to create something that would be useful to me.\\nUsing my engineering background, home automation experience and limited development background I endeavored to be the puppet master\\nand steer AI to develop what I wanted.  Here we are... here we go!"}]}}')}}]);